query:
-- Takım Çalışması ve İşbirliği
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '1', 'Çalışma ortamında iyi ilişkiler kurar ve korur.', 1 
FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '2', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.', 2 
FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '3', 'Takım ruhuna uyumlu yaklaşımda bulunur.', 3 
FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '4', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.', 4 
FROM position_categories WHERE positionId = 8 AND name = 'Takım Çalışması ve İşbirliği' LIMIT 1;

-- Müşteri Odaklılık
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '1', 'Müşteri ihtiyaçlarını anlar ve bu ihtiyaçları doğru şekilde tanımlar.', 1 
FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '2', 'Müşteri sorunlarına hızlı ve etkili çözümler bulur.', 2 
FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '3', 'Müşterisine karşı anlayışlı, sabırlı ve saygılı bir iletişim tarzı benimser.', 3 
FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '4', 'Müşteri memnuniyeti artırmaya yönelik çalışmalara katkıda bulunur.', 4 
FROM position_categories WHERE positionId = 8 AND name = 'Müşteri Odaklılık' LIMIT 1;

-- Ticari Bakış
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '1', 'Yaptığı işin sonuçlarının kurumun beklediği ticari sonuçlar ile paralel olmasını gözetir.', 1 
FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '2', 'Uygun durumlarda, satış fırsatlarını geliştirecek alternatif yaklaşımlar tavsiye eder.', 2 
FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '3', 'Kurumun müşteri sayısını geliştirmeye yönelik çalışmalarda bulunur.', 3 
FROM position_categories WHERE positionId = 8 AND name = 'Ticari Bakış' LIMIT 1;

-- Planlama ve Organize Etme
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '1', 'Görevlerini sahip olduğu zamanı dikkate alarak gereken sürede tamamlar.', 1 
FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '2', 'Birden fazla işe odaklanarak bunları eş zamanlı yürütebilir.', 2 
FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '3', 'Planlama ile ilgili öncelikleri saptar, yetki sınırları içinde doğru sıralamayı gerçekleştirir.', 3 
FROM position_categories WHERE positionId = 8 AND name = 'Planlama ve Organize Etme' LIMIT 1;

-- İş Disiplini ve Tutum
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '1', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder.', 1 
FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '2', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.', 2 
FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '3', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.', 3 
FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '4', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.', 4 
FROM position_categories WHERE positionId = 8 AND name = 'İş Disiplini ve Tutum' LIMIT 1;

-- Kasa
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '1', 'Kasa işlemlerini hatasız bir şekilde yapar.', 1 
FROM position_categories WHERE positionId = 8 AND name = 'Kasa' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '2', 'Nakit ve avans yönetimini prosedürlere uygun hareket eder.', 2 
FROM position_categories WHERE positionId = 8 AND name = 'Kasa' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '3', 'Müşteri ödemelerini doğru ve güvenli bir şekilde alır.', 3 
FROM position_categories WHERE positionId = 8 AND name = 'Kasa' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '4', 'Kasa kapatma işlemlerini titiz bir şekilde gerçekleştirir.', 4 
FROM position_categories WHERE positionId = 8 AND name = 'Kasa' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '5', 'Gıda Güvenliği ve İSG kurallarına uygun hareket eder.', 5 
FROM position_categories WHERE positionId = 8 AND name = 'Kasa' LIMIT 1;
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) 
SELECT id, '6', 'Çalıştığı ekipmanları özenli ve titiz kullanır.', 6 
FROM position_categories WHERE positionId = 8 AND name = 'Kasa' LIMIT 1;

